import{_ as a,o as p,c as t,j as r,a as _,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"5.2.加_减值概述","description":"","frontmatter":{},"headers":[],"relativePath":"1.基础规则/5.强化规则/5.2.加_减值概述.md","filePath":"1.基础规则/5.强化规则/5.2.加_减值概述.md"}'),s={name:"1.基础规则/5.强化规则/5.2.加_减值概述.md"};function o(d,e,b,l,i,c){return p(),t("div",null,[...e[0]||(e[0]=[r("h1",{id:"_5-2-加-减值概述",tabindex:"-1"},[_("5.2.加_减值概述 "),r("a",{class:"header-anchor",href:"#_5-2-加-减值概述","aria-label":'Permalink to "5.2.加_减值概述"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001A")])])],-1),n('<h1 id="加-减值概述" tabindex="-1">加/减值概述 <a class="header-anchor" href="#加-减值概述" aria-label="Permalink to &quot;加/减值概述&quot;">​</a></h1><p>加值：<br> 部分主神的强化可以为人物提供数据上的加值，每一个加值都拥有它自己的类型。除非特别说明，否则当你在一个项目（例如属性、判定、防御）上获得的多个同类型的加值总是会叠加生效。<br> 加值分为判定DP加值和增加附加成功两种，这两种加值视为不同的两类。<br> 例如技能A提供人物+2增强加值，技能B提供人物+1来源为增强加值的附加成功，人物可以同时获得+2DP+1附加成功，两者均为增强加值。</p><p>加值分为以下几种：</p><p>内在<br> 内在加值是一类由于人物的本身发生改变而产生的加值，只会加在属性上（这意味着，不会出现攻击上和防御上的内在加值）。通过强化内在能力、从主神处购买属性，以及某些强化提供的属性加值，皆为内在加值。<br> 例如血统、改造、瞳术带来的永久性加值都是内在加值（但这些项目带来的特殊能力如变身、狂暴、黑暗冲动等的加值一般不是）。</p><p>修行<br> 修行加值是指人物修习某种技能或能力而获得的加值，只会加在属性和检定上（这意味着，不会出现防御上的修行加值）。</p><p>增强<br> 增强加值可能是各种因素带来，一般加在某种属性、一类判定，或者一个较小的项目上（例如，不是防御上获得增强加值，而是在盔甲上获得增强加值），它意味着某种因素使你的一个方面被单纯地强化了。增强加值视为被它强化的项目的一部分（例如，一件防弹衣在盔甲防御上获得+2增强加值，则在加值有效时间内它视为一件防御4的装甲）。</p><p>器械<br> 器械加值一般由某种工具带来，加在某种技能判定上（这意味着，不会出现防御上的器械加值），它意味着这件工具设计合理易用、功能强大，非常称手。相对的，当一件工具不称手时，你会受到器械减值。<br> 液态金属头盔带来的攻击加值，或艾杰利商业电脑带来的电脑工作判定加值都是器械加值。所有原先的助动加值，均被认为是器械加值。</p><p>专业<br> 专业加值由你所学习的“专业”带来，加在专业对应的技能判定上。它意味着你对某一类工作得心应手。</p><p>速度<br> 速度加值一般是因为你的移动或出手速度带来的效果，一般加在攻击判定上（这意味着，不会出现防御上的速度加值）。</p><p>表现/士气加值<br> 表现加值一般加在防御或某种判定上，它意味着由于经验、灵感、情绪或内在的力量提升了你的状态，使得你能在某一方面做的更好。消耗意志力以及基因锁带来的加值都是额外的表现加值。<br> 其中，因情绪带来的表现加值又被称作士气加值。士气加值同样可能加在防御或某种判定上，它反映了调动人物情绪的效果。<br> 承受“恐惧”和“沮丧”点数的人物会额外减少同等数量的攻击和防御上的表现/士气加值（二者同时减少，最低减到0）。</p><p>技艺<br> 技艺加值一般加在攻击或其他战斗相关的项目上（这意味着，不会出现防御上的技艺加值，一个技艺提供的防御大多是格挡、闪避、洞察等类型），由你使用或维持的特殊能力带来。</p><p>加值总是被归类于以上分类中的一种。</p><p>减值：<br> 减值是一种特殊情况，不良状态会产生减值，另一些能力可以为人物造成减值。有些血统或特殊能力会使被强化者在某一方面产生减值。部分减值也可以应用加值的类型，当同类型的加值和减值同时存在时，用以下办法处理：<br> 取数值最大的加值和数值最大的减值，它们同时生效。</p><p>减值分为以下几种：</p><p>环境减值：环境减值一般是指因恶劣的环境而承受的减值，如昏暗环境、无法适应的环境等情况而承受的减值。</p><p>士气减值/表现减值：士气减值/表现减值一般是指士气低落、表现不佳等情况而承受的减值，大部分异常点数带来的减值都是士气减值/表现减值。</p><p>器械减值：器械减值一般是因器械不合体或无法正常使用带来的减值，如未达到武器力量需求或盔甲减值都是器械减值。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',19)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
